class DSU{
private:
    ll row, col;
    vector < vector < pair < ll, ll > > > parent;
public:
    DSU(ll row, ll col): row(row), col(col){
        parent.resize(this->row, vector < pair < ll, ll > >(col));
        for(int i=0; i<row; i++){
            for(int j=0; j<col; j++){
                parent[i][j] = {i, j};
            }
        }
    }

    pair < ll, ll > getParent(ll x, ll y){
        if(parent[x][y].first == x && parent[x][y].second == y)
            return {x, y};
        return parent[x][y] = getParent(parent[x][y].first, parent[x][y].second);
    }

    void setUnion(ll cx, ll cy, ll sx, ll sy){
        pair < ll, ll > cp = getParent(cx, cy);
        pair < ll, ll > sp = getParent(sx, sy);
        if(cp == sp)
            return;
        parent[cp.first][cp.second] = sp;
    }
};
class Island{
private:
    DSU dsu;
    vector < vector < bool > > visit;
    ll dx[4] = {-1, 0, 1, 0};
    ll dy[4] = {0, -1, 0, 1};
    bool isValid(ll x, ll y, ll row, ll col){
        return x>=0 && y>=0 && x<row && y<col;
    }
public:


    Island(ll row, ll col): dsu(row, col), visit(row, vector < bool > (col, false)){
    }
    void addIsland(ll x, ll y){
        visit[x][y] = true;
        for(int i=0; i<4; i++){
            ll tx = x + dx[i];
            ll ty = y + dy[i];
            if(isValid(tx, ty, visit.size(), visit[0].size()) && visit[tx][ty]){
                dsu.setUnion(x, y, tx, ty);
            }
        }
    }
    bool isIsland(ll x, ll y){
        return visit[x][y];
    }
    ll getIsland(){
        set < pair < ll, ll > > st;
        for(int i=0; i<visit.size(); i++){
            for(int j=0; j<visit[i].size(); j++){
                if(visit[i][j]){
                    debug(i, j, visit[i][j]);
                    st.insert(dsu.getParent(i, j));
                }
            }
        }
        return st.size();
    }
};

